type DisplayComment struct {
	Author           string
	Timestamp        time.Time
	FormattedContent template.HTML
}

type PageData struct {
	Comments []DisplayComment
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}

	tmpl, err := template.New("comments").Parse(pageTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Template parse error: %v", err)
		return
	}

	displayComments := make([]DisplayComment, len(comments))
	for i, c := range comments {
		displayComments[i] = DisplayComment{
			Author:           c.Author,
			Timestamp:        c.Timestamp,
			FormattedContent: sanitizeHTML(c.Content),
		}
	}

	data := PageData{
		Comments: displayComments,
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := tmpl.Execute(w, data); err != nil {
		log.Printf("Template execution error: %v", err)
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)

	addr := ":8080"
	log.Printf("Starting server on %s", addr)
	log.Printf("Visit http://localhost%s to view comments", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}